345	static int post_process_obj_detect(image_bytes img, struct EEPTPU_RESULT& result)
346	{
347	    clear_objects();
348	    
349	    if ( (result.shape[1] * result.shape[2] * result.shape[3] == 0) || (result.shape[1] != 1) )
350	    {
351	        printf("Nothing detected !\n");
352	        return 0;
353	    }
354	
355	    for (int i = 0; i < result.shape[2]; i++)
356	    {
357	        const float *values = result.data + i * result.shape[3];
358	
359	        Object object;
360	        object.label = values[0];
361	        object.prob = values[1];
362	        object.x = values[2] * img.w;
363	        object.y = values[3] * img.h;
364	        object.w = values[4] * img.w - object.x;
365	        object.h = values[5] * img.h - object.y;
366	        strcpy(object.obj_class_name, class_names[object.label]);
367	        
368	        if (object.x < 0) { object.w += object.x; object.x = 0; }
369	        if (object.y < 0) { object.h += object.y; object.y = 0; }
370	
371	        g_objects.push_back(object);
372	    }
373	   
374	    printf("Detection result: \n");
375	    for (unsigned int i = 0; i < g_objects.size(); i++)
376	    {
377	        const Object &obj = g_objects[i];
378	        printf("    [%d] %d = %.5f at %d %d %d x %d   (%s)\n", i, obj.label, obj.prob,
379	                obj.x, obj.y, obj.w, obj.h, class_names[obj.label]);
380	    }
381	        
382	    return 0;
383	}
