385	static image_bytes draw_objects(image_bytes img, const std::vector<Object> &objects)
386	{    
387	    image_bytes image = eepimg_copy_image(img);
388	
389	    for (size_t i = 0; i < objects.size(); i++)
390	    {
391	        const Object &obj = objects[i];
392	        image = eepimg_draw_box(image, 
393	                                obj.x, obj.y, 
394	                                obj.x+obj.w, obj.y+obj.h,
395	                                0, 255, 0, 1);
396	        
397	        sprintf(text, "%s %.1f%%", class_names[obj.label], obj.prob * 100);
398	        int x = obj.x;
399	        int y = obj.y;
400	        image = eepimg_draw_text(image, x, y, text);
401	    }
402	
403	    return image;
404	}
