408	static int get_topk(const std::vector<float>& cls_scores, unsigned int topk, std::vector< std::pair<float, int> >& top_list)
409	{
410	    if (cls_scores.size() < topk) topk = cls_scores.size();
411	
412	    int size = cls_scores.size();
413	    std::vector< std::pair<float, int> > vec;
414	    vec.resize(size);
415	    for (int i=0; i<size; i++)
416	    {
417	        vec[i] = std::make_pair(cls_scores[i], i);
418	    }
419	
420	    std::partial_sort(vec.begin(), vec.begin() + topk, vec.end(),
421	                      std::greater< std::pair<float, int> >());
422	    
423	    top_list.resize(topk);
424	    for (unsigned int i=0; i<topk; i++)
425	    {
426	        top_list[i].first = vec[i].first;
427	        top_list[i].second = vec[i].second;
428	    }
429	
430	    return 0;
431	}
432	
433	static int get_topk(struct EEPTPU_RESULT& result , int topk, std::vector< std::pair<float, int> >& top_list)
434	{
435	    std::vector<float> cls_scores;
436	    cls_scores.resize(result.shape[1]*result.shape[2]*result.shape[3]);
437	    
438	    int c = 0;
439	    for (int i = 0; i < result.shape[1]*result.shape[2]*result.shape[3]; i++)
440	    {
441	        cls_scores[c++] = result.data[i];
442	    }
443	
444	    return get_topk(cls_scores, topk, top_list);
445	}
